(function(window, document){
    "use strict";
    function getActionSelectors(actionNameOrSysId) {
        return [
            '[data-action-name="' + actionNameOrSysId + '"]',
            '[gsft_id="' + actionNameOrSysId + '"]',
            '[id="' + actionNameOrSysId + '"]',
            '[gsft_action_name="' + actionNameOrSysId + '"]'
        ].join(',');
    }
    function setUIActionVisibility(actionNameOrSysId, visible) {
        const elements = document.querySelectorAll(getActionSelectors(actionNameOrSysId));
        elements.forEach(element => {
            element.style.display = visible ? 'block' : 'none';
        });
        return elements.length > 0;
    }
    function setUIActionDisabled(actionNameOrSysId, disabled) {
        const elements = document.querySelectorAll(getActionSelectors(actionNameOrSysId));
        elements.forEach(element => {
            element.disabled = disabled;
        });
        return elements.length > 0;
    }
    class GlideActions {
        constructor() {
        }
        getActions(){
            const ids = new Set();
            const actions = [];
            document.querySelectorAll('[gsft_id].form_action_button, [gsft_id].navigation_link').forEach(node => {
                if (!ids.has(node.getAttribute("gsft_id") || node.id)) {
                    ids.add(node.getAttribute("gsft_id") || node.id);
                    actions.push(new GlideAction(node, this));
                }
            });
            return actions;
        }
        getAction(actionNameOrSysId){
            const node = document.querySelector(getActionSelectors(actionNameOrSysId));
            return node ? new GlideAction(node, this) : null;
        }
        updateActionLabel(actionNameOrSysId, label){
            const nodes = document.querySelectorAll(getActionSelectors(actionNameOrSysId));
            nodes.forEach(node => node.innerText = label);
            return nodes.length > 0;
        }
        showAction(actionNameOrSysId) {
            setUIActionVisibility(actionNameOrSysId, true);
        }
        hideAction(actionNameOrSysId) {
            setUIActionVisibility(actionNameOrSysId, false);
        }
        disableAction(actionNameOrSysId) {
            setUIActionDisabled(actionNameOrSysId, true);
        }
        enableAction(actionNameOrSysId){
            setUIActionDisabled(actionNameOrSysId, false);
        }
    }
    class GlideAction {
        constructor(actionElement, actionsContext) {
            this._actionElement = actionElement;
            this._actions = actionsContext;
        }
        get name() {
            return this.getActionName();
        }
        get label() {
            return this.getActionLabel();
        }
        get sysId() {
            return this.getActionId();
        }
        getActionName() {
            return this._actionElement.getAttribute("data-action-name") || this._actionElement.getAttribute("gsft_action_name");
        }
        getActionLabel() {
            return this._actionElement.textContent;
        }
        getActionId() {
            return this._actionElement.getAttribute("gsft_id") || this._actionElement.id;
        }
        show() {
            this._actions.showAction(this.getActionId());
        }
        hide() {
            this._actions.hideAction(this.getActionId());
        }
        updateLabel(label) {
            this._actions.updateActionLabel(this.getActionId(), label);
        }
        disable() {
            this._actions.disableAction(this.getActionId());
        }
        enable() {
            this._actions.enableAction(this.getActionId());
        }
    }
    window.GlideActions = GlideActions;
})(window, document);
