GlideTimeElement.formatTime = function(hour, minute, second, ampm, format) {
	var value=new Object();
	if (ampm=="PM")
		hour += 12;
	value["H"]=hour;
value["HH"]=LZ(hour);
	if (hour==0)
		value["h"]=12;
	else if (hour>12)
		value["h"]=hour-12;
	else
		value["h"]=hour;
	value["hh"]=LZ(value["h"]);
	value["a"]=ampm;
	value["aa"]=ampm;
	value["m"]=minute;
	value["mm"]=LZ(minute);
	value["s"]=second;
	value["ss"]=LZ(second);
	var i_format=0;
	var c="";
	var result="";
	while (i_format < format.length) {
		c=format.charAt(i_format);
		token="";
		while ((format.charAt(i_format)==c) && (i_format < format.length)) {
			token += format.charAt(i_format++);
		}
		if (value[token] != null)
			result=result + value[token];
		else
			result=result + token;
	}
	return result;
}
