		CATEGORIES.forEach(function(cat) {
			if (!categories[cat.category])
				return;
			else {
				totalCategories =  totalCategories + 1;
				var ms = _getTiming(cat.category) + '';
				if ('RLV2' !== cat.category)
					other -= ms;
			}
		});
		return other > 10 ? (totalCategories + 1) : totalCategories;
